131→async fn render_contexts_with_error(
132→    pool: &PgPool,
133→    user_id: &crate::domain::UserId,
134→    error_message: &str,
135→) -> Result<Response, ContextError> {
136→    let contexts = list_contexts(pool, user_id)
137→        .await
138→        .map_err(ContextError::Unexpected)?;
139→
140→    let inbox_count = inbox_service::get_inbox_count(pool, user_id)
141→        .await
142→        .map_err(ContextError::Unexpected)?;
143→
144→    let context_views: Vec<ContextView> = contexts.iter().map(ContextView::from).collect();
145→
146→    let template = ContextsTemplate {
147→        current_page: "contexts",
148→        inbox_count,
149→        contexts: context_views,
150→        error_message: Some(error_message.to_string()),
151→    };
152→    let body = template.render().map_err(ContextError::Render)?;
153→    Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
154→}
