156→pub async fn get_edit_context(
157→    AuthenticatedUser(user_id): AuthenticatedUser,
158→    State(pool): State<PgPool>,
159→    headers: HeaderMap,
160→    Path(context_id): Path<Uuid>,
161→) -> Result<Response, ContextError> {
162→    let ctx_id = ContextId::from_uuid(context_id);
163→    let context = crate::infrastructure::context_repository::find_context_by_id(&pool, &ctx_id)
164→        .await
165→        .map_err(|e| ContextError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
166→        .ok_or_else(|| ContextError::Unexpected(anyhow::anyhow!("Context not found")))?;
167→
168→    if context.user_id() != &user_id {
169→        return Ok((
170→            StatusCode::FORBIDDEN,
171→            Html("<h1>Not authorized</h1>".to_string()),
172→        )
173→            .into_response());
174→    }
175→
176→    let htmx = is_htmx_request(&headers);
177→
178→    if htmx {
179→        let template = ContextEditTemplate {
180→            context: ContextView::from(&context),
181→        };
182→        let body = template.render().map_err(ContextError::Render)?;
183→        Ok(Html(body).into_response())
184→    } else {
185→        // Full page -- redirect to contexts page for non-HTMX
186→        Ok(Redirect::to("/contexts").into_response())
187→    }
188→}
