195→pub async fn post_edit_context(
196→    AuthenticatedUser(user_id): AuthenticatedUser,
197→    State(pool): State<PgPool>,
198→    headers: HeaderMap,
199→    Path(context_id): Path<Uuid>,
200→    Form(form): Form<EditContextForm>,
201→) -> Result<Response, ContextError> {
202→    let htmx = is_htmx_request(&headers);
203→    let ctx_id = ContextId::from_uuid(context_id);
204→
205→    match update_context(&pool, &ctx_id, &user_id, form.name).await {
206→        Ok(()) => {
207→            if htmx {
208→                let context =
209→                    crate::infrastructure::context_repository::find_context_by_id(&pool, &ctx_id)
